def first_missing_positive(xs):
    if not xs:
        return 1

    n = len(xs)
    has_one = 0 in xs

    for i in range(n):
        if xs[i] <= 0 or xs[i] > n:
            xs[i] = 1

    for x in xs:
        if abs(x) == n:
            xs[0] = -abs(xs[0])
        elif abs(x) < n:
            xs[abs(x)] = -abs(xs[abs(x)])

    for i in range(1, n):
        if xs[i] > 0:
            return i

    if xs[0] > 0:
        return n

    return n + 1
